# Q3 additions bank — only what's needed
Q3_BANK = {1: Q3_L1_ADD, 2: Q3_L2_ADD, 4: Q3_L4_ADD, 9: Q3_L9}


def insert_questions(quarter, bank, subject_id=1, grade=6):
    """Insert questions from bank into DB. Bank: {lesson_num: [(text, a, b, c, d, correct), ...]}"""
    inserted = 0
    for lesson, items in bank.items():
        for idx, item in enumerate(items):
            text, opt_a, opt_b, opt_c, opt_d, correct = item
            # Shuffle options to avoid all correct = A
            opts = [(opt_a, 'A'), (opt_b, 'B'), (opt_c, 'C'), (opt_d, 'D')]
            # Find correct option text
            correct_text = opts[ord(correct) - ord('A')][0]
            # Shuffle
            random.shuffle(opts)
            new_a = opts[0][0]
            new_b = opts[1][0]
            new_c = opts[2][0]
            new_d = opts[3][0]
            # Find new correct letter
            for i, (txt, _) in enumerate(opts):
                if txt == correct_text:
                    new_correct = chr(ord('A') + i)
                    break
            # Difficulty: 10% hard, 30% easy, 60% medium
            r = random.random()
            if r < 0.1:
                difficulty = 3
            elif r < 0.4:
                difficulty = 1
            else:
                difficulty = 2
            q = Question(
                subject_id=subject_id, grade=grade, quarter=quarter,
                difficulty=difficulty, lesson=lesson,
                question_text=text, option_a=new_a, option_b=new_b,
                option_c=new_c, option_d=new_d, correct_answer=new_correct,
            )
            db.session.add(q)
            inserted += 1
    db.session.commit()
    return inserted


def main():
    app = create_app()
    with app.app_context():
        print("Inserting Q2 questions...")
        n2 = insert_questions(2, Q2_BANK)
        print(f"  Q2: {n2} new questions")

        print("Inserting Q3 additional questions...")
        n3 = insert_questions(3, Q3_BANK)
        print(f"  Q3: {n3} new questions")

        print("Inserting Q4 questions...")
        n4 = insert_questions(4, Q4_BANK)
        print(f"  Q4: {n4} new questions")

        # Final state
        from sqlalchemy import func
        print("\n=== Final state ===")
        for q in [1, 2, 3, 4]:
            n = Question.query.filter_by(subject_id=1, grade=6, quarter=q).count()
            print(f"Q{q}: {n}")


if __name__ == '__main__':
    main()
